import type { NotificationPayload } from '@motivation/shared';
import { createNotificationClickMessage } from './sw-messages.js';

export interface ShowableRegistration {
    showNotification(title: string, options?: NotificationOptions): Promise<void>;
}

export interface ClickableClient {
    id?: string;
    url?: string;
    focus?: () => Promise<unknown>;
    postMessage(message: unknown): void;
}

export interface ClientsLike {
    matchAll(options: { type: 'window'; includeUncontrolled: boolean }): Promise<ClickableClient[]>;
    openWindow?(url: string): Promise<ClickableClient | null>;
}

const DEFAULT_PAYLOAD: NotificationPayload = {
    title: 'Motivation',
    body: 'You have a new update.',
    tag: 'motivation',
    data: { path: '/' },
};

export function parsePushPayload(raw: unknown): NotificationPayload {
    if (!raw || typeof raw !== 'object') return DEFAULT_PAYLOAD;
    const candidate = raw as Partial<NotificationPayload>;
    const data = (candidate.data && typeof candidate.data === 'object')
        ? candidate.data as NotificationPayload['data']
        : { path: '/' };

    return {
        title: typeof candidate.title === 'string' && candidate.title.length > 0 ? candidate.title : DEFAULT_PAYLOAD.title,
        body: typeof candidate.body === 'string' ? candidate.body : DEFAULT_PAYLOAD.body,
        tag: typeof candidate.tag === 'string' && candidate.tag.length > 0 ? candidate.tag : DEFAULT_PAYLOAD.tag,
        data: {
            path: typeof data.path === 'string' && data.path.length > 0 ? data.path : '/',
            category: data.category,
        },
    };
}

export async function showPushNotification(
    registration: ShowableRegistration,
    rawPayload: unknown,
): Promise<NotificationPayload> {
    const payload = parsePushPayload(rawPayload);
    await registration.showNotification(payload.title, {
        body: payload.body,
        tag: payload.tag,
        data: payload.data,
    });
    return payload;
}

export interface NotificationClickContext {
    clients: ClientsLike;
    origin: string;
    basePath: string;
}

export async function handleNotificationClick(
    ctx: NotificationClickContext,
    data: unknown,
): Promise<void> {
    const path = (data && typeof data === 'object' && typeof (data as { path?: unknown }).path === 'string')
        ? (data as { path: string }).path
        : '/';
    const targetUrl = new URL(
        `${ctx.basePath.replace(/\/$/, '')}${path.startsWith('/') ? path : `/${path}`}`,
        ctx.origin,
    ).href;

    const clients = await ctx.clients.matchAll({ type: 'window', includeUncontrolled: true });
    for (const client of clients) {
        if (client.focus) await client.focus();
        client.postMessage(createNotificationClickMessage({ path }));
        return;
    }

    if (ctx.clients.openWindow) {
        await ctx.clients.openWindow(targetUrl);
    }
}
