import { CLIENT_LOG_SYNC_TAG, shipPendingClientLogs } from './client-log-shipping.js';

export interface ClientLogSyncEventLike {
    readonly tag: string;
    waitUntil(promise: Promise<unknown>): void;
}

export function handleClientLogSyncEvent(
    event: ClientLogSyncEventLike,
    ship: () => Promise<unknown> = shipPendingClientLogs,
): boolean {
    if (event.tag !== CLIENT_LOG_SYNC_TAG) return false;
    event.waitUntil(ship());
    return true;
}
