import {
    shipPendingImageUploads,
} from './image-upload-shipping.js';
import { IMAGE_UPLOAD_SYNC_TAG } from './image-upload-store.js';

/**
 * Tiny SW-side dispatcher mirroring `client-log-sync-handler.ts`. Returns
 * true when it claimed the event so the SW can chain other sync handlers.
 */
export interface ImageUploadSyncEventLike {
    readonly tag: string;
    waitUntil(promise: Promise<unknown>): void;
}

export function handleImageUploadSyncEvent(
    event: ImageUploadSyncEventLike,
    ship: () => Promise<unknown> = shipPendingImageUploads,
): boolean {
    if (event.tag !== IMAGE_UPLOAD_SYNC_TAG) return false;
    event.waitUntil(ship());
    return true;
}
